parameters.jsCode:
const raw = $input.first().json.output[0].content[0].text;

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error(`OpenAI did not return valid JSON: ${error.message}\nRaw response: ${raw}`);
}

return [
  {
    json: {
      topic: parsed.topic,
      angle: parsed.angle,
      audience: Array.isArray(parsed.audience)
        ? parsed.audience.join(", ")
        : parsed.audience,
      audience_raw: parsed.audience,
      summary: parsed.summary,
      key_points: parsed.key_points || [],
      suggested_hook: parsed.suggested_hook,
      visual_ideas: parsed.visual_ideas || [],
      risks_to_verify: parsed.risks_to_verify || [],
      trend_score: parsed.score?.trend_score,
      audience_fit_score: parsed.score?.audience_fit_score,
      competition_score: parsed.score?.competition_score,
      production_effort_score: parsed.score?.production_effort_score,
      evergreen_score: parsed.score?.evergreen_score,
      monetization_score: parsed.score?.monetization_score,
      final_priority_score: parsed.score?.final_priority_score,
      content_score_json: parsed,
      content_score_json_raw: raw
    }
  }
];

