parameters.jsCode:
const score = $('Parse OpenAI Content JSON').first().json;

// Soporta salida tipo Gemini:
// $json.content.parts[0].text
//
// Y también salida tipo Claude:
// $json.content[0].text

let scriptText = '';

if ($json.content?.parts?.[0]?.text) {
  scriptText = $json.content.parts[0].text;
} else if (Array.isArray($json.content) && $json.content[0]?.text) {
  scriptText = $json.content[0].text;
} else {
  throw new Error('No script text found in AI response');
}

return {
  json: {
    workflow_run_id: $('Create Workflow Run').first().json.id,

    topic: score.topic,
    angle: score.angle,
    audience: score.audience,

    summary: score.summary,
    key_points: score.key_points || [],
    suggested_hook: score.suggested_hook,
    visual_ideas: score.visual_ideas || [],
    risks_to_verify: score.risks_to_verify || [],

    trend_score: score.trend_score,
    audience_fit_score: score.audience_fit_score,
    competition_score: score.competition_score,
    production_effort_score: score.production_effort_score,
    evergreen_score: score.evergreen_score,
    monetization_score: score.monetization_score,
    final_priority_score: score.final_priority_score,

    content_score_json: score.content_score_json,

    script_text: scriptText
  }
};

const payload = $('Normalize AI Script Output').first().json;
const insertedIdea = $('Insert Content Idea').first().json;

if (!insertedIdea.id) {
  throw new Error('Insert Content Idea did not return an id');
}

if (insertedIdea.id === payload.workflow_run_id) {
  throw new Error('Invalid mapping: inserted idea id equals workflow_run_id');
}

return {
  json: {
    idea_id: insertedIdea.id,
    title: payload.topic,
    status: 'draft',
    brief: {
      summary: payload.summary,
      key_points: payload.key_points,
      suggested_hook: payload.suggested_hook,
      visual_ideas: payload.visual_ideas,
      risks_to_verify: payload.risks_to_verify,
      score: payload.content_score_json?.score || {}
    },
    sources: [],
    payload
  }
};

const prepared = $('Prepare Research Brief Row').first().json;
const researchBrief = $('Insert Research Brief').first().json;

if (!researchBrief.id) {
  throw new Error('Insert Research Brief V2 did not return an id');
}

return {
  json: {
    ...prepared.payload,
    idea_id: prepared.idea_id,
    research_brief_id: researchBrief.id
  }
};

const payload = $json;

if (!payload.idea_id) {
  throw new Error('Missing idea_id');
}

if (!payload.research_brief_id) {
  throw new Error('Missing research_brief_id');
}

if (!payload.script_text) {
  throw new Error('Missing script_text');
}

return {
  json: {
    idea_id: payload.idea_id,
    research_brief_id: payload.research_brief_id,
    title: payload.topic,
    hook: payload.suggested_hook,
    script_text: payload.script_text,
    status: 'draft',
    metadata: {
      workflow_run_id: payload.workflow_run_id,
      angle: payload.angle,
      audience: payload.audience,
      final_priority_score: payload.final_priority_score,
      content_score: payload.content_score_json
    },
    payload
  }
};

const script = $('Insert Script V2').first().json;
const preparedScript = $('Prepare Script Row').first().json;
const payload = preparedScript.payload;

if (!script.id) {
  throw new Error('Insert Script V2 did not return an id');
}

if (!payload.workflow_run_id) {
  throw new Error('Missing workflow_run_id');
}

return {
  json: {
    workflow_run_id: payload.workflow_run_id,
    status: 'completed',
    finished_at: new Date().toISOString(),
    output: {
      idea_id: payload.idea_id,
      research_brief_id: payload.research_brief_id,
      script_id: script.id,
      topic: payload.topic,
      final_priority_score: payload.final_priority_score
    }
  }
};
